{
    "level": "A1–A2",
    "intro": "У цій темі ти швидко закріпиш <strong>am / is / are</strong>, заперечення, короткі питання та моделі <strong>there is / there are</strong>.",
    "rules": [
        {
            "label": "Present Forms",
            "color": "emerald",
            "text": "Почни з форм <strong>am / is / are</strong> у простих реченнях.",
            "example": "I am late. / She is ready. / They are here."
        },
        {
            "label": "Questions",
            "color": "blue",
            "text": "З <strong>to be</strong> питання будуються без <strong>do / does</strong>.",
            "example": "Are you ready? / Is he at home?"
        },
        {
            "label": "There Is / Are",
            "color": "amber",
            "text": "Окремо потренуй моделі для опису наявності в місці.",
            "example": "There is a book on the table."
        }
    ]
}

{
    "title": "1. Стартовий набір",
    "intro": "Цей підрозділ іде від найпростіших форм до базових питань і моделей з there.",
    "items": [
        {
            "label": "A1",
            "title": "Present Forms",
            "subtitle": "am / is / are у коротких стверджувальних реченнях."
        },
        {
            "label": "A1",
            "title": "Negatives",
            "subtitle": "am not, is not, are not і поширені скорочення."
        },
        {
            "label": "A1",
            "title": "Questions and Short Answers",
            "subtitle": "Am I...?, Is he...?, Are they...? і короткі відповіді."
        },
        {
            "label": "A1–A2",
            "title": "There Is / There Are",
            "subtitle": "Опис того, що є або немає в певному місці."
        }
    ]
}

{
    "title": "2. Що ти відпрацюєш",
    "sections": [
        {
            "label": "am / is / are",
            "color": "emerald",
            "description": "Побачиш, яку форму брати з <strong>I</strong>, <strong>he / she / it</strong> та <strong>you / we / they</strong>.",
            "examples": [
                {
                    "en": "I am tired. / She is a student. / They are at work.",
                    "ua": "Базові моделі для стану, ролі та місця."
                }
            ]
        },
        {
            "label": "not і питання",
            "color": "blue",
            "description": "Навчишся ставити <strong>not</strong> після to be та переносити форму <strong>перед підмет</strong> у питаннях.",
            "examples": [
                {
                    "en": "He is not busy. / Are they ready?",
                    "ua": "Заперечення і питання без додаткового допоміжного дієслова."
                }
            ]
        },
        {
            "label": "There is / There are",
            "color": "amber",
            "description": "Зможеш сказати, що є або немає в кімнаті, будинку, сумці чи місті.",
            "examples": [
                {
                    "en": "There are two chairs in the kitchen.",
                    "ua": "Опис наявності предметів у місці."
                }
            ]
        }
    ]
}

{
    "title": "3. Коротко",
    "items": [
        "<strong>Present Forms</strong> дає базу для речень з <strong>am / is / are</strong>.",
        "<strong>Negatives</strong> показує форми з <strong>not</strong> і скорочення <strong>isn't / aren't</strong>.",
        "<strong>Questions and Short Answers</strong> тренує інверсію з <strong>to be</strong> і короткі відповіді.",
        "<strong>There Is / There Are</strong> допомагає говорити про наявність у місці.",
        "Разом ці уроки закривають перший A1-блок для <strong>to be</strong>."
    ]
}
